import { d3_polygonContains } from '../../../core/d3-constants';

export function PolySearch(nodes) {
    this.data = nodes;
}

var proto = PolySearch.prototype;

proto.getPoly = function(d) {
    return d._polydata().points;
};

proto.find = function(mouse) {
    var points = [];
    this.data.map((d, i) => {
        if (d._data()._visible) {
            points.push(d);
        }
    });
    return points;
};
